function footerRuntime(){var e=Global.theme_config.footerStart;window.setTimeout("footerRuntime()",1e3),X=new Date(e),Y=new Date,T=Y.getTime()-X.getTime(),M=864e5,a=T/M,A=Math.floor(a),b=24*(a-A),B=Math.floor(b),c=60*(b-B),C=Math.floor(60*(b-B)),D=Math.floor(60*(c-C)),runtime_days.innerHTML=A,runtime_hours.innerHTML=B,runtime_minutes.innerHTML=C,runtime_seconds.innerHTML=D}window.addEventListener("DOMContentLoaded",footerRuntime);